// ====== Import unic: Raportări istorice din bonuri e:Corg (apr 2025 -> ) + cash/POS din cash-vs-card ======
function importRaportariIstoric(){
  if(typeof RAPORTARI_ISTORIC==='undefined' || !RAPORTARI_ISTORIC.length){ toast('Nimic de importat'); return; }
  var _mid=function(s){ return String(s||'').trim().split(/\s+/)[0]; };
  var have={}; (DB.raportari||[]).forEach(function(r){ have[r.data+'|'+_mid(r.magazin)]=1; });
  var willAdd=RAPORTARI_ISTORIC.filter(function(x){ return !have[x.data+'|'+_mid(x.magazin)]; }).length;
  if(!confirm('Import raportări istorice (bonuri e:Corg): '+RAPORTARI_ISTORIC.length+' rânduri.\n'+willAdd+' se adaugă, '+(RAPORTARI_ISTORIC.length-willAdd)+' se sar (există deja).\nBackup automat înainte. Continui?')) return;
  try{ createBackup('pre-import-raportari-istoric-'+todayISO()); }catch(e){}
  if(!DB.raportari) DB.raportari=[];
  var add=0,skip=0;
  RAPORTARI_ISTORIC.forEach(function(x){
    var k=x.data+'|'+_mid(x.magazin);
    if(have[k]){ skip++; return; } have[k]=1;
    DB.raportari.push({data:x.data,magazin:x.magazin,casier:x.casier||'',vanzari:x.vanzari||0,pos:(x.pos===''?'':x.pos),
      numerarTeoretic:(x.numerarTeoretic===''?'':x.numerarTeoretic),numerarPredat:(x.numerarPredat===''?'':x.numerarPredat),
      diferenta:x.diferenta||0,bonuri:x.bonuri||0,anulari:0,retururi:0,difStoc:0,alerta:'OK',motiv:'',detalii:'',
      observatii:x.observatii||'back-fill bonuri',salvatLa:nowISO(),auto:true,sursaImport:'backfill-receipts'});
    add++;
  });
  save(); try{ renderRaportare(); }catch(e){}
  toast('✓ Istoric importat: '+add+' adăugate, '+skip+' sărite.');
}
